  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// ✅ Recommended: require authentication + strip sensitive fields for non-admin
app.get('/users', authenticate, authorize('read:users'), (req, res) => {
  const users = getUsers();
  const safeUsers = users.map(({ id, name }) => ({ id, name })); // No email
  res.json(safeUsers);
});
```

